/* ---------------------------------------------------------
   CONEXÃO COM O SUPABASE
   Painel interno de verdade: login autentica contra o Supabase
   Auth, e os dados (clientes/processos/despesas/recebimentos)
   vêm das tabelas reais, respeitando as políticas de acesso
   (RLS) — só usuário autenticado enxerga qualquer linha.
--------------------------------------------------------- */
const SUPABASE_URL = 'https://mdaseywjzekmzcpqfeaf.supabase.co';
const SUPABASE_ANON_KEY = 'sb_publishable_b3CnodU_8mfi4XbqjIvWcA_ogW3_vq2';

async function supabaseLogin(email, senha) {
  const res = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', apikey: SUPABASE_ANON_KEY },
    body: JSON.stringify({ email, password: senha }),
  });
  const data = await res.json().catch(() => ({}));
  if (!res.ok) {
    throw new Error(data.error_description || data.msg || 'E-mail ou senha inválidos.');
  }
  return data.access_token;
}

async function supabaseSelect(table, accessToken) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?select=*`, {
    headers: { apikey: SUPABASE_ANON_KEY, Authorization: `Bearer ${accessToken}` },
  });
  if (!res.ok) throw new Error(`Não foi possível carregar "${table}".`);
  return res.json();
}

const MESES_ABREV = ['Jan', 'Fev', 'Mar', 'Abr', 'Mai', 'Jun', 'Jul', 'Ago', 'Set', 'Out', 'Nov', 'Dez'];

// Formata datas vindas do Postgres (YYYY-MM-DD...) sem depender de fuso horário
function formatDataBR(isoDate) {
  if (!isoDate) return '—';
  const [y, m, d] = isoDate.slice(0, 10).split('-');
  return `${d}/${m}/${y}`;
}

function mesLabel(isoDate) {
  const mm = parseInt(isoDate.slice(5, 7), 10) - 1;
  return MESES_ABREV[mm] || isoDate;
}

function statusStyle(status) {
  if (status === 'Em andamento') return { bg: '#F1E7D6', text: C.brass, dot: C.brass };
  if (status === 'Aguardando decisão') return { bg: '#F1E0E2', text: C.burgundy, dot: C.burgundy };
  return { bg: '#E7EEE7', text: C.sage, dot: C.sage };
}

function gerarProtocolo() {
  const now = new Date();
  const n = Math.floor(1000 + Math.random() * 9000);
  return `${now.getFullYear()}.${String(now.getMonth() + 1).padStart(2, '0')}.${n}`;
}

